SELECT MAX(tax_amount) AS max_tax_amount
FROM tax_records
WHERE year = 2022;

SELECT SUM(tax_amount) AS total_tax_paid
FROM tax_records
WHERE property_id = 1 AND year = 2022;

SELECT category_name
FROM property_categories
WHERE category_id = 1;

SELECT COUNT(valuation_id) AS total_valuations
FROM property_valuations
WHERE year = 2017;

SELECT value_assigned
FROM property_valuations
WHERE year = 2023;
